/**
 * SHINERVA - Robust Email Service with SMTP-to-Gmail Fallback
 * ===========================================================
 * Primary: Custom domain SMTP (admin@shinerva.id / support@shinerva.id)
 * Fallback: Gmail (hello.shinerva@gmail.com)
 *
 * Handles: Magic Link generation + delivery, Email Verification,
 * Password Reset, and any transactional emails.
 *
 * Token integrity: All tokens are generated by Firebase Admin SDK on the
 * server — email transport only handles delivery. Token cannot be tampered
 * with by the transport layer.
 */

import nodemailer from 'nodemailer';
import admin from 'firebase-admin';

// ─── Transporter Initialization ───────────────────────────────────────────────
const createPrimaryTransport = () => {
  const host = process.env.EMAIL_HOST;
  const port = Number(process.env.EMAIL_PORT) || 587;
  const secure = process.env.EMAIL_SECURE === 'true';

  if (!host || !process.env.EMAIL_USER || !process.env.EMAIL_PASS) {
    return null;
  }

  return nodemailer.createTransport({
    host,
    port,
    secure, // true = 465, false = 587/STARTTLS
    auth: {
      user: process.env.EMAIL_USER,
      pass: process.env.EMAIL_PASS,
    },
    // Connection pool settings
    pool: true,
    maxConnections: 5,
    maxMessages: 100,
    // Timeout settings
    connectionTimeout: 15000,  // 15s to establish connection
    greetingTimeout: 15000,
    socketTimeout: 30000,      // 30s per operation
  });
};

const createFallbackTransport = () => {
  if (!process.env.FALLBACK_EMAIL || !process.env.FALLBACK_EMAIL_PASSWORD) {
    return null;
  }
  return nodemailer.createTransport({
    service: 'gmail',
    auth: {
      user: process.env.FALLBACK_EMAIL,
      pass: process.env.FALLBACK_EMAIL_PASSWORD,
    },
    pool: true,
    maxConnections: 3,
    maxMessages: 50,
    connectionTimeout: 15000,
    socketTimeout: 30000,
  });
};

let primaryTransport = null;
let fallbackTransport = null;
let firebaseAdminAuth = null;

function initServices() {
  primaryTransport = createPrimaryTransport();
  fallbackTransport = createFallbackTransport();

  // Get Firebase Admin auth instance
  try {
    const firebaseApp = admin.apps.length > 0 ? admin.apps[0] : null;
    if (firebaseApp) {
      firebaseAdminAuth = admin.auth(firebaseApp);
    }
  } catch (_) {
    console.warn('[Email] Firebase Admin not available — token generation disabled');
  }
}

initServices();


/**
 * Verifies SMTP connection health before attempting send.
 * Catches connection errors early to switch transporter proactively.
 */
async function probeTransport(transport, label) {
  try {
    await new Promise((resolve, reject) => {
      transport.verify((error, success) => {
        if (error) reject(error);
        else resolve(success);
      });
    });
    return true;
  } catch (err) {
    console.warn(`[Email] ${label} probe failed: ${err.message}`);
    return false;
  }
}

// ─── Magic Link Token Generation ─────────────────────────────────────────────

/**
 * Generates a Firebase magic link token server-side using Firebase Admin SDK.
 * This token is cryptographically signed by Firebase — the email transport
 * only delivers the URL. Token integrity is guaranteed by Firebase.
 *
 * @param {string} email - Recipient email
 * @param {string} continueUrl - URL to redirect after click
 * @returns {Promise<string>} - Complete magic link URL
 */
export async function generateMagicLinkToken(email, continueUrl) {
  if (!firebaseAdminAuth) {
    throw new Error('Firebase Admin Auth not initialized');
  }

  const actionCodeSettings = {
    url: continueUrl || process.env.EMAIL_CONTINUE_URL || process.env.APP_URL || 'https://shinerva.id',
    handleCodeInApp: true,
  };

  try {
    const link = await firebaseAdminAuth.generateSignInWithEmailLink(email, actionCodeSettings);
    console.log(`[Email] Magic link generated for ${email}`);
    return link;
  } catch (err) {
    console.error(`[Email] Magic link generation failed for ${email}:`, err.message);
    throw new Error(`Gagal membuat link masuk: ${err.message}`);
  }
}

