// ─── Core Send Function ─────────────────────────────────────────────────────

/**
 * Sends an email with full primary→fallback cascade.
 *
 * Cascade logic:
 *  1. Try to send via primary custom domain SMTP (admin@shinerva.id / support@shinerva.id)
 *  2. On primary error (network, auth, SMTP rejection): immediately catch and fall back to Gmail
 *  3. On Gmail error: throw with combined error info
 *
 * The email content (from/subject/html) is built BEFORE sending, so the
 * same template is used regardless of which transport delivers it.
 * The magic link token is pre-generated by Firebase Admin SDK — the
 * transport only carries the pre-signed URL.
 *
 * @param {string} to - Recipient email
 * @param {string} subject - Email subject
 * @param {string} html - Email HTML body
 * @returns {{ success: true, transport: string }}
 */
export async function sendEmail({ to, subject, html }) {

  // Determine from address
  const primaryUser = process.env.EMAIL_USER || '';
  const allowedPrimary = ['admin@shinerva.id', 'support@shinerva.id'];
  const fromAddress = process.env.EMAIL_FROM
    || (allowedPrimary.includes(primaryUser) ? primaryUser : 'support@shinerva.id');

  const mailOptions = { from: fromAddress, to, subject, html };

  // ── Try Primary SMTP ──────────────────────────────────────────────────────
  if (primaryTransport) {
    try {
      await primaryTransport.sendMail(mailOptions);
      console.log(`[Email] ✓ Sent via primary SMTP (${fromAddress}) → ${to}`);
      return { success: true, transport: 'primary SMTP', from: fromAddress };
    } catch (primaryErr) {
      console.warn(`[Email] Primary SMTP failed for ${to}: ${primaryErr.message} (code: ${primaryErr.code})`);
      
      const isAuthErr = primaryErr.code === 'EAUTH' || primaryErr.message?.includes('Authentication') || primaryErr.responseCode === 535;
      if (isAuthErr) {
        console.warn('[Email] Primary SMTP auth failed — permanently disabling primary transport');
        primaryTransport = null;
      }
      
      console.log('[Email] Triggering global fallback mechanism...');
      // Proceed to Gmail fallback immediately
    }
  } else {
    console.warn('[Email] Primary SMTP not configured or disabled — using fallback Gmail');
  }

  // ── Fallback Gmail ────────────────────────────────────────────────────────
  if (fallbackTransport) {
    try {
      // Override from address for Gmail fallback, but keep exact same template structure
      const fallbackFrom = process.env.FALLBACK_EMAIL || 'hello.shinerva@gmail.com';
      const gmailOptions = {
        ...mailOptions,
        from: fallbackFrom,
      };
      
      await fallbackTransport.sendMail(gmailOptions);
      console.log(`[Email] ✓ Sent via fallback Gmail (${fallbackFrom}) → ${to}`);
      return { success: true, transport: 'fallback Gmail', from: fallbackFrom };
    } catch (fallbackErr) {
      console.error(`[Email] Fallback Gmail also failed for ${to}: ${fallbackErr.message}`);
      throw new Error(`Gagal mengirim email. Silakan coba lagi atau hubungi support. (Gmail error: ${fallbackErr.message})`);
    }
  }

  // ── No transport available ────────────────────────────────────────────────
  throw new Error('Tidak ada konfigurasi email yang aktif. Pastikan SMTP atau Gmail sudah diset.');
}

// ─── Convenience Wrappers ─────────────────────────────────────────────────────

/**
 * Sends a magic link email to the given address.
 * Generates the token server-side, sends via best available transport.
 */
export async function sendMagicLinkEmail({ to, continueUrl }) {
  const link = await generateMagicLinkToken(to, continueUrl);
  const { subject, html } = buildMagicLinkEmail(link, to);
  return sendEmail({ to, subject, html });
}

/**
 * Sends an email verification link.
 * Note: Firebase Admin SDK cannot send verification emails directly.
 * This requires the user's ID token which is only available client-side.
 * Use the client SDK's sendEmailVerification() for now, or pass the ID token
 * to this server function if you prefer SMTP delivery.
 */
export async function sendVerificationEmail({ to, idToken: _idToken, continueUrl }) {
  // idToken param kept for signature compatibility — Firebase Admin generates the
  // verification link server-side without needing the client's ID token.
  if (!firebaseAdminAuth) {
    throw new Error('Firebase Admin not available for verification email');
  }
  try {
    // Generate verification link server-side using the user's ID token
    const link = await firebaseAdminAuth.generateEmailVerificationLink(to, {
      url: continueUrl || process.env.EMAIL_CONTINUE_URL || process.env.APP_URL || 'https://shinerva.id',
    });
    const { subject, html } = buildVerificationEmail(link, to);
    return sendEmail({ to, subject, html });
  } catch (err) {
    console.error(`[Email] Verification email failed for ${to}:`, err.message);
    throw new Error(`Gagal mengirim email verifikasi: ${err.message}`);
  }
}

/**
 * Sends a password reset email.
 */
export async function sendPasswordResetEmail({ to }) {
  if (!firebaseAdminAuth) {
    throw new Error('Firebase Admin not available for password reset');
  }
  try {
    const link = await firebaseAdminAuth.generatePasswordResetLink(to);
    const { subject, html } = buildPasswordResetEmail(link);
    return sendEmail({ to, subject, html });
  } catch (err) {
    console.error(`[Email] Password reset failed for ${to}:`, err.message);
    throw new Error(`Gagal mengirim email reset password: ${err.message}`);
  }
}

// ─── Health Check ────────────────────────────────────────────────────────────

/**
 * Returns email service health status for diagnostics.
 */
export async function getEmailHealth() {
  const checks = {};

  if (primaryTransport) {
    checks.primary = await probeTransport(primaryTransport, 'primary SMTP');
  } else {
    checks.primary = 'not_configured';
  }

  if (fallbackTransport) {
    checks.fallback = await probeTransport(fallbackTransport, 'fallback Gmail');
  } else {
    checks.fallback = 'not_configured';
  }

  checks.firebaseAdminAuth = !!firebaseAdminAuth;

  return checks;
}
